1	import { describe, expect, it } from "vitest";
2	import { adjudicateLine } from "../src/domain/adjudication/adjudicator";
3	import { aCoverageRule, aLineItem, anAccumulator, anAdjudicateInput } from "./builders";
4	
5	describe("adjudicateLine — no coverage rule", () => {
6	  it("denies the line with NO_COVERAGE and pays nothing when no rule matches the service", () => {
7	    // Arrange — the one load-bearing fact: there is no coverage rule for this service.
8	    const line = aLineItem({ serviceCode: "EXPERIMENTAL_THERAPY", billedCents: 12_000 });
9	    const input = anAdjudicateInput({ line, rule: undefined });
10	
11	    // Act
12	    const result = adjudicateLine(input);
13	
14	    // Assert — a no-coverage line is a *processed* denial (HTTP 200 decision), not an error.
15	    expect(result.status).toBe("DENIED");
16	    expect(result.payableCents).toBe(0); // plan pays nothing
17	    expect(result.memberResponsibilityCents).toBe(0); // not a cost-share; member owes the provider directly
18	
19	    // Dominant code is NO_COVERAGE.
20	    expect(result.reasons).toEqual(["NO_COVERAGE"]);
21	
22	    // A gate denial touches no accumulator.
23	    expect(result.deltas).toEqual({ deductibleIncCents: 0, oopIncCents: 0, limitInc: 0 });
24	
25	    // The explanation says why, in plain words.
26	    expect(result.explanation).toMatch(/no.*coverage|not covered/i);
27	  });
28	});
29	
30	describe("adjudicateLine — excluded service", () => {
31	  it("denies the line with EXCLUDED and pays nothing when the rule excludes the service", () => {
32	    // Arrange — the one load-bearing fact: a rule exists but the service is excluded.
33	    const rule = aCoverageRule({ serviceCode: "ADULT_DENTAL", excluded: true });
34	    const line = aLineItem({ serviceCode: "ADULT_DENTAL", billedCents: 20_000 });
35	    const input = anAdjudicateInput({ line, rule });
36	
37	    // Act
38	    const result = adjudicateLine(input);
39	
40	    // Assert — an excluded line is a processed denial, distinct from "no rule at all".
41	    expect(result.status).toBe("DENIED");
42	    expect(result.payableCents).toBe(0); // plan pays nothing
43	    expect(result.memberResponsibilityCents).toBe(0); // not a cost-share
44	
45	    // Dominant code is EXCLUDED (not NO_COVERAGE).
46	    expect(result.reasons).toEqual(["EXCLUDED"]);
47	
48	    // A gate denial touches no accumulator.
49	    expect(result.deltas).toEqual({ deductibleIncCents: 0, oopIncCents: 0, limitInc: 0 });
50	
51	    // The explanation says it's an excluded benefit.
52	    expect(result.explanation).toMatch(/exclud/i);
53	  });
54	});
55	
56	describe("adjudicateLine — rule present but not covered", () => {
57	  it("denies with NO_COVERAGE when a rule exists but covered is false", () => {
58	    const rule = aCoverageRule({ serviceCode: "COSMETIC", covered: false });
59	    const line = aLineItem({ serviceCode: "COSMETIC", billedCents: 30_000 });
