5	// The one-transaction-per-claim boundary is a `withTransaction` runner injected as a dep, so the
6	// raw Db never leaks into the service.
7	
8	import { adjudicateLine } from "../domain/adjudication/adjudicator";
9	import type { ClaimStatus } from "../domain/entities/claim";
10	import {
11	  type LineOutcome,
12	  aggregateClaimStatus,
13	} from "../domain/state-machines/claim-state";
14	import type { AccumulatorRepository } from "../repositories/accumulator.repository";
15	import type { AdjudicationRepository } from "../repositories/adjudication.repository";
16	import type { ClaimRepository } from "../repositories/claim.repository";
17	import type { CoverageRuleRepository } from "../repositories/coverage-rule.repository";
18	import type { PolicyRepository } from "../repositories/policy.repository";
19	
20	export type ClaimServiceDeps = {
21	  claims: ClaimRepository;
22	  adjudications: AdjudicationRepository;
23	  accumulators: AccumulatorRepository;
24	  coverageRules: CoverageRuleRepository;
25	  policies: PolicyRepository;
26	  withTransaction: <T>(fn: () => T) => T;
27	};
28	
29	export type AdjudicateClaimInput = {
30	  memberId: string;
31	  serviceDate: string;
32	  provider?: string;
33	  diagnosisCode?: string;
34	  lineItems: {
35	    serviceCode: string;
36	    billedCents: number;
37	    units?: number;
38	    priorAuthPresent?: boolean;
39	  }[];
40	};
41	
42	export type AdjudicateClaimResult = { claimId: string; status: ClaimStatus };
43	
44	export function createClaimService(deps: ClaimServiceDeps) {
45	  function adjudicateClaim(input: AdjudicateClaimInput): AdjudicateClaimResult {
46	    return deps.withTransaction(() => {
47	      const policy = deps.policies.findActiveForMember(
48	        input.memberId,
49	        input.serviceDate,
50	      );
51	      if (!policy) {
52	        throw new Error(
53	          `no active policy for member ${input.memberId} on ${input.serviceDate}`,
54	        );
55	      }
56	      const planYear = String(policy.planYear);
57	      const ruleByService = new Map(
58	        deps.coverageRules
59	          .findByPolicy(policy.id)
60	          .map((r) => [r.serviceCode, r]),
61	      );
62	
63	      const claimId = deps.claims.insertClaim({
64	        memberId: input.memberId,
65	        policyId: policy.id,
66	        serviceDate: input.serviceDate,
67	        provider: input.provider ?? null,
68	        diagnosisCode: input.diagnosisCode ?? null,
69	      });
70	
71	      // One snapshot at claim start; deltas applied to this working copy between lines so a later
72	      // line sees an earlier line's deductible/OOP/limit draw (determinism — cycle 20).
73	      const acc = deps.accumulators.snapshot(input.memberId, planYear);
74	      const touched = {
75	        deductible: false,
76	        oop: false,
77	        limits: new Set<string>(),
78	      };
79	      const outcomes: LineOutcome[] = [];
80	
81	      for (const li of input.lineItems) {
82	        const fingerprint = `${input.memberId}|${li.serviceCode}|${input.serviceDate}|${li.billedCents}`;
83	        const line = deps.claims.insertLine(claimId, {
84	          serviceCode: li.serviceCode,
85	          billedCents: li.billedCents,
86	          units: li.units,
87	          priorAuthPresent: li.priorAuthPresent,
88	          fingerprint,
89	        });
90	
91	        const result = adjudicateLine({
92	          line: {
93	            id: line.id,
94	            claimId,
95	            serviceCode: line.serviceCode,
96	            billedCents: line.billedCents,
97	            units: line.units,
98	            priorAuthPresent: line.priorAuthPresent,
99	            status: "PENDING",
100	            fingerprint,
101	          },
102	          policy,
103	          rule: ruleByService.get(li.serviceCode),
104	          serviceDate: input.serviceDate,
105	          acc: {
106	            deductibleMetCents: acc.deductibleMetCents,
107	            oopMetCents: acc.oopMetCents,
108	            limitUsed: acc.limitUsedByService[li.serviceCode] ?? 0,
109	          },
110	          alreadyAdjudicated: false,
111	        });
112	
113	        deps.adjudications.append({
114	          lineItemId: line.id,
115	          planYear,
116	          seq: 1, // first decision for this line; a dispute re-adjudication appends a higher seq
117	          // adjudicateLine only ever decides APPROVED | DENIED (never PENDING/NEEDS_REVIEW)
118	          status: result.status as "APPROVED" | "DENIED",
119	          billedCents: line.billedCents,
120	          payableCents: result.payableCents,
121	          memberResponsibilityCents: result.memberResponsibilityCents,
122	          reasons: result.reasons,
123	          explanation: result.explanation,
124	          deltas: result.deltas,
125	        });
126	        deps.claims.setLineStatus(line.id, result.status);
127	
128	        if (result.deltas.deductibleIncCents > 0) {
129	          acc.deductibleMetCents += result.deltas.deductibleIncCents;
130	          touched.deductible = true;
131	        }
132	        if (result.deltas.oopIncCents > 0) {
133	          acc.oopMetCents += result.deltas.oopIncCents;
134	          touched.oop = true;
135	        }
136	        if (result.deltas.limitInc > 0) {
137	          acc.limitUsedByService[li.serviceCode] =
138	            (acc.limitUsedByService[li.serviceCode] ?? 0) +
139	            result.deltas.limitInc;
140	          touched.limits.add(li.serviceCode);
141	        }
142	
143	        outcomes.push({ status: result.status, reasons: result.reasons });
144	      }
145	
146	      // persist only the dimensions this claim actually touched (rows are created lazily)
147	      if (touched.deductible) {
148	        deps.accumulators.upsert({
149	          memberId: input.memberId,
150	          planYear,
151	          dimension: "DEDUCTIBLE",
152	          unit: "CENTS",
153	          usedCents: acc.deductibleMetCents,
154	          usedCount: 0,
155	        });
156	      }
157	      if (touched.oop) {
158	        deps.accumulators.upsert({
159	          memberId: input.memberId,
160	          planYear,
161	          dimension: "OOP",
162	          unit: "CENTS",
163	          usedCents: acc.oopMetCents,
164	          usedCount: 0,
165	        });
166	      }
167	      for (const service of touched.limits) {
168	        const isVisits = ruleByService.get(service)?.limit.unit === "visits";
169	        const used = acc.limitUsedByService[service] ?? 0;
170	        deps.accumulators.upsert({
171	          memberId: input.memberId,
172	          planYear,
173	          dimension: `LIMIT:${service}`,
174	          unit: isVisits ? "COUNT" : "CENTS",
175	          usedCents: isVisits ? 0 : used,
176	          usedCount: isVisits ? used : 0,
177	        });
178	      }
179	
180	      const status = aggregateClaimStatus(outcomes);
181	      deps.claims.setClaimStatus(claimId, status);
182	      return { claimId, status };
183	    });
184	  }
185	
186	  return { ...deps, adjudicateClaim };
187	}
188	
189	export type ClaimService = ReturnType<typeof createClaimService>;

