58	function diffOutcome(original: Decision, next: Decision): DisputeOutcome {
59	  if (original.status === "DENIED" && next.status === "APPROVED") {
60	    return next.reasons.includes("LIMIT_EXCEEDED")
61	      ? "PARTIALLY_OVERTURNED"
62	      : "OVERTURNED";
63	  }
64	  const unchanged =
65	    original.status === next.status &&
66	    original.payableCents === next.payableCents &&
67	    JSON.stringify(original.reasons) === JSON.stringify(next.reasons);
68	  return unchanged ? "UPHELD" : "MODIFIED";
69	}
