72	  function open(input: OpenDisputeInput): OpenDisputeResult {
73	    return deps.withTransaction(() => {
74	      const line = deps.claims.findLineById(input.lineItemId);
75	      if (!line) throw new Error(`line item not found: ${input.lineItemId}`);
76	      const original = deps.adjudications.currentForLine(input.lineItemId);
77	      if (!original)
78	        throw new Error(
79	          `no adjudication to dispute for line ${input.lineItemId}`,
80	        );
81	
82	      const claim = deps.claims.findClaimById(line.claimId);
83	      if (!claim) throw new Error(`claim not found: ${line.claimId}`);
84	      const policy = deps.policies.findActiveForMember(
85	        claim.memberId,
86	        claim.serviceDate,
