97	          .map((r) => [r.serviceCode, r]),
98	      );
99	
100	      // Reopen: the terminal line moves to NEEDS_REVIEW, initiated by the MEMBER.
101	      deps.setStatus({
102	        claimId: claim.id,
103	        target: { type: "LINE_ITEM", id: line.id, status: "NEEDS_REVIEW" },
104	        fromStatus: original.status,
105	        actor: "MEMBER",
106	        reason: "DISPUTE_REOPEN",
107	      });
108	
109	      // Overlay the corrected facts (the only amendable line fields) and re-adjudicate against
110	      // current rules. The net-out of the original deltas is a no-op when the disputed decision
111	      // contributed nothing (e.g. a denial); it is exercised rigorously at cycle 35.
112	      const corrected = input.corrected ?? {};
113	      const effServiceCode = corrected.serviceCode ?? line.serviceCode;
114	      const effBilledCents = corrected.billedCents ?? line.billedCents;
115	      const effUnits = corrected.units ?? line.units;
116	      const effPriorAuth = corrected.priorAuthPresent ?? line.priorAuthPresent;
117	
118	      const acc = deps.accumulators.snapshot(claim.memberId, planYear);
119	      const result = adjudicateLine({
