122	          claimId: line.claimId,
123	          serviceCode: effServiceCode,
124	          billedCents: effBilledCents,
125	          units: effUnits,
126	          priorAuthPresent: effPriorAuth,
127	          status: "PENDING",
128	          fingerprint: line.fingerprint,
129	        },
130	        policy,
131	        rule: ruleByService.get(effServiceCode),
132	        serviceDate: claim.serviceDate,
133	        acc: {
134	          deductibleMetCents: acc.deductibleMetCents,
