83	
84	    // Each line's CURRENT decision (its max-seq adjudication) for one claim — for re-aggregation.
85	    currentOutcomesByClaim(
86	      claimId: string,
87	    ): { status: "APPROVED" | "DENIED"; reasons: ReasonCode[] }[] {
88	      const rows = db.all<{
89	        status: "APPROVED" | "DENIED";
90	        reasons_json: string;
91	      }>(sql`
92	        SELECT a.status AS status, a.reasons_json AS reasons_json
93	        FROM line_items li
94	        JOIN adjudications a ON a.line_item_id = li.id
95	        WHERE li.claim_id = ${claimId}
96	          AND a.seq = (SELECT MAX(seq) FROM adjudications WHERE line_item_id = li.id)
97	      `);
98	      return rows.map((r) => ({
99	        status: r.status,
100	        reasons: JSON.parse(r.reasons_json) as ReasonCode[],
101	      }));
102	    },
103	  };
104	}
