107	  typeof createAdjudicationRepository
108	>;

16	//   otherwise (every line fully APPROVED)        → APPROVED          (cycle 22)
17	// A straddled line is itself APPROVED but carries LIMIT_EXCEEDED (its plan pay was capped at
18	// the remaining dollar limit and the shortfall fell to the member) — a partial payout.
19	export function aggregateClaimStatus(lines: LineOutcome[]): ClaimStatus {
20	  if (lines.every((line) => line.status === "DENIED")) return "DENIED";
21	
22	  const anyDenied = lines.some((line) => line.status === "DENIED");
23	  const anyStraddled = lines.some(
24	    (line) =>
25	      line.status === "APPROVED" && line.reasons.includes("LIMIT_EXCEEDED"),
26	  );
27	  if (anyDenied || anyStraddled) return "PARTIALLY_APPROVED";
28	
29	  return "APPROVED";
30	}

