70	// Diff the new decision against the original (decision #16 outcome taxonomy).
71	function diffOutcome(original: Decision, next: Decision): DisputeOutcome {
72	  if (original.status === "DENIED" && next.status === "APPROVED") {
73	    return next.reasons.includes("LIMIT_EXCEEDED")
74	      ? "PARTIALLY_OVERTURNED"
